import React, { memo, useCallback, useMemo, useEffect, Suspense, lazy } from 'react';
import { PiBackspaceThin } from "react-icons/pi";
import { CiSearch } from "react-icons/ci";
import { CiCirclePlus } from "react-icons/ci";
import { CiCircleChevDown } from "react-icons/ci";
import { CiSquareCheck } from "react-icons/ci";
import WinModalQuest from '../../../UI/WinModalQuest/WinModalQuest';
import InputMessage from '../../../UI/InputBoardList/InputMessage/InputMessage';
import { useFormatDate } from '../hooks/useFormatDate';
import { PiTrashThin, PiDotsThreeBold } from "react-icons/pi";
import './bookmark_modal.css';

const OptionInPost = lazy(() => import('../OptionInPost/OptionInPost'));

const BookmarkModal = memo(({
    showBookmarkModal,
    handleCloseBookmark,
    bookmarkRefs,
    activeTab,
    setActiveTab,
    showSearchFields,
    setShowSearchFields,
    searchQuery,
    setSearchQuery,
    searchDate,
    setSearchDate,
    bookmarkedPosts,
    setBookmarkedPosts,
    customBookmarks,
    setCustomBookmarks,
    handleDeleteBookmarkClick,
    handleDeleteCustomBookmarkClick,
    isBookmarkAdded,
    handleAddToPostsClick,
    handleToggleBookmarkExpansion,
    expandedBookmarks,
    overflowingBookmarks,
    showTextInput,
    setShowTextInput,
    customBookmarkText,
    setCustomBookmarkText,
    handleCreateCustomBookmark,
    resetExpandedBookmarks
}) => {
    const [showDeleteBookmarkModal, setShowDeleteBookmarkModal] = React.useState(false);
    const [showDeleteCustomBookmarkModal, setShowDeleteCustomBookmarkModal] = React.useState(false);
    const [showDeleteAllBookmarkModal, setShowDeleteAllBookmarkModal] = React.useState(false);
    const [showDeleteAllCustomBookmarkModal, setShowDeleteAllCustomBookmarkModal] = React.useState(false);
    const [bookmarkToDelete, setBookmarkToDelete] = React.useState(null);
    const [customBookmarkToDelete, setCustomBookmarkToDelete] = React.useState(null);
    const [showAddToPostsModal, setShowAddToPostsModal] = React.useState(false);
    const [bookmarkToAdd, setBookmarkToAdd] = React.useState(null);
    const [visibleOpcionId, setVisibleOpcionId] = React.useState(null);
    const [showCopySuccess, setShowCopySuccess] = React.useState(null);
    const [selectedMessageId, setSelectedMessageId] = React.useState(null);
    const [showDeleteModal, setShowDeleteModal] = React.useState(false);
    const [showBookmarkSuccess, setShowBookmarkSuccess] = React.useState(null);
    const [showInput, setShowInput] = React.useState(false);
    const [inputText, setInputText] = React.useState('');
    const [editingMessageId, setEditingMessageId] = React.useState(null);
    const [editingText, setEditingText] = React.useState('');
    const [selectedFile, setSelectedFile] = React.useState(null);

    // ✅ Выносим функцию форматирования наверх
    const formatDate = useFormatDate;

    React.useEffect(() => {
        function handleKeyDown(event) {
            if (event.key === 'Tab') {
                event.preventDefault();
                const createBlock = document.querySelector('.create_bookmark_block');
                if (createBlock) {
                    createBlock.click();
                }
            }
        }
        document.addEventListener('keydown', handleKeyDown);
        return () => {
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, []);

    // ✅ Используем formatDate вместо хука
    const filterBookmarks = useCallback((bookmarks, query, date) => {
        return bookmarks.filter(bookmark => {
            const matchesText = query ? bookmark.text.toLowerCase().includes(query.toLowerCase()) : true;
            const matchesDate = date ? formatDate(bookmark.timestamp) === formatDate(new Date(date)) : true;
            return matchesText && matchesDate;
        });
    }, [formatDate]); // ✅ Добавили зависимость

    const handleDeleteBookmark = useCallback((bookmarkId) => {
        setBookmarkToDelete(bookmarkId);
        setShowDeleteBookmarkModal(true);
    }, []);

    const handleDeleteCustomBookmark = useCallback((bookmark) => {
        setCustomBookmarkToDelete(bookmark);
        setShowDeleteCustomBookmarkModal(true);
    }, []);

    const confirmDeleteBookmark = useCallback(() => {
        if (bookmarkToDelete) {
            handleDeleteBookmarkClick(bookmarkToDelete);
            setBookmarkToDelete(null);
        }
        setShowDeleteBookmarkModal(false);
    }, [bookmarkToDelete, handleDeleteBookmarkClick]);

    const confirmDeleteCustomBookmark = useCallback(() => {
        if (customBookmarkToDelete) {
            handleDeleteCustomBookmarkClick(customBookmarkToDelete);
            setCustomBookmarkToDelete(null);
        }
        setShowDeleteCustomBookmarkModal(false);
    }, [customBookmarkToDelete, handleDeleteCustomBookmarkClick]);

    const cancelDeleteBookmark = useCallback(() => {
        setBookmarkToDelete(null);
        setShowDeleteBookmarkModal(false);
    }, []);

    const cancelDeleteCustomBookmark = useCallback(() => {
        setCustomBookmarkToDelete(null);
        setShowDeleteCustomBookmarkModal(false);
    }, []);

    const handleAddToPosts = useCallback((bookmark) => {
        setBookmarkToAdd(bookmark);
        setShowAddToPostsModal(true);
    }, []);

    const confirmAddToPosts = useCallback(() => {
        if (bookmarkToAdd) {
            handleAddToPostsClick(bookmarkToAdd);
            setBookmarkToAdd(null);
        }
        setShowAddToPostsModal(false);
    }, [bookmarkToAdd, handleAddToPostsClick]);

    const cancelAddToPosts = useCallback(() => {
        setBookmarkToAdd(null);
        setShowAddToPostsModal(false);
    }, []);

    const handleSearchClick = useCallback(() => {
        setShowSearchFields(prev => !prev);
    }, [setShowSearchFields]);

    const handleTabChange = useCallback((tab) => {
        resetExpandedBookmarks();
        setActiveTab(tab);
    }, [setActiveTab, resetExpandedBookmarks]);

    const handleTextInputToggle = useCallback(() => {
        setShowTextInput(true);
        setActiveTab('text');
    }, [setShowTextInput, setActiveTab]);

    const handleFileSelect = useCallback((file) => {
        setSelectedFile(file);
    }, []);

    const handleCustomBookmarkSend = useCallback((text, file) => {
        if (editingMessageId) {
            const isBookmark = bookmarkedPosts.some(b => b.id === editingMessageId);
            if (isBookmark) {
                setBookmarkedPosts(prev => prev.map(b => b.id === editingMessageId ? { ...b, text, timestamp: new Date() } : b));
            } else {
                setCustomBookmarks(prev => prev.map(b => b.id === editingMessageId ? { ...b, text, timestamp: new Date() } : b));
            }
            setEditingMessageId(null);
            setCustomBookmarkText('');
            setShowTextInput(false);
            setSelectedFile(null);
        } else {
            if (text.trim() || file) {
                handleCreateCustomBookmark(text, file);
                setCustomBookmarkText('');
                setShowTextInput(false);
                setSelectedFile(null);
            }
        }
    }, [editingMessageId, bookmarkedPosts, setBookmarkedPosts, setCustomBookmarks, handleCreateCustomBookmark]);

    const handleCustomBookmarkClose = useCallback(() => {
        setCustomBookmarkText('');
        setShowTextInput(false);
        setEditingMessageId(null);
        setSelectedFile(null);
    }, []);

    const handleCustomBookmarkKeyPress = useCallback((e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            if (editingMessageId) {
                const isBookmark = bookmarkedPosts.some(b => b.id === editingMessageId);
                if (isBookmark) {
                    setBookmarkedPosts(prev => prev.map(b => b.id === editingMessageId ? { ...b, text: customBookmarkText, timestamp: new Date() } : b));
                } else {
                    setCustomBookmarks(prev => prev.map(b => b.id === editingMessageId ? { ...b, text: customBookmarkText, timestamp: new Date() } : b));
                }
                setEditingMessageId(null);
                setCustomBookmarkText('');
                setShowTextInput(false);
                setSelectedFile(null);
            } else {
                if (customBookmarkText.trim() || selectedFile) {
                    handleCreateCustomBookmark(customBookmarkText, selectedFile);
                    setCustomBookmarkText('');
                    setShowTextInput(false);
                    setSelectedFile(null);
                }
            }
        }
    }, [editingMessageId, customBookmarkText, selectedFile, bookmarkedPosts, setBookmarkedPosts, setCustomBookmarks, handleCreateCustomBookmark]);

    // Мемоизированные данные для рендеринга
    const filteredBookmarkedPosts = useMemo(() =>
        filterBookmarks(bookmarkedPosts, searchQuery, searchDate)
            .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp)),
        [bookmarkedPosts, searchQuery, searchDate, filterBookmarks]
    );

    const filteredCustomBookmarks = useMemo(() =>
        filterBookmarks(customBookmarks, searchQuery, searchDate)
            .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp)),
        [customBookmarks, searchQuery, searchDate, filterBookmarks]
    );

    if (!showBookmarkModal) return null;

    const renderBookmarkItem = (bookmark, isCustom = false) => (
        <div key={`${bookmark.id}-${bookmark.timestamp.getTime()}`} className="bookmark_item">
            <PiDotsThreeBold className='option_bookmark' onClick={() => setVisibleOpcionId(visibleOpcionId === bookmark.id ? null : bookmark.id)} />
            {isBookmarkAdded(bookmark.id) ? (
                <CiSquareCheck
                    className='add_to_posts_btn'
                    style={{ color: isCustom ? 'rgba(5, 255, 5, 0.839)' : 'rgb(255, 145, 0)' }}
                />
            ) : (
                <CiCirclePlus
                    className='add_to_posts_btn'
                    style={{ color: isCustom ? '#fff12fb4' : undefined }}
                    onClick={() => handleAddToPosts(bookmark)}
                />
            )}

            {bookmark.text && bookmark.text.trim() && (
                <div
                    ref={el => bookmarkRefs.current.set(bookmark.id, el)}
                    className={`bookmark_text ${expandedBookmarks.has(bookmark.id) ? 'expanded' : ''}`}
                    style={{
                        height: expandedBookmarks.has(bookmark.id) ? 'auto' : '1.8em',
                        overflow: expandedBookmarks.has(bookmark.id) ? 'visible' : 'hidden'
                    }}
                >
                    {bookmark.text}
                </div>
            )}
            {((bookmark.text && bookmark.text.trim()) || (bookmark.file && bookmark.file.length > 0)) && (
                <CiCircleChevDown
                    className={`look_all ${expandedBookmarks.has(bookmark.id) ? 'rotated' : ''}`}
                    style={{ color: expandedBookmarks.has(bookmark.id) ? 'violet' : 'rgba(55, 255, 175, 0.77)' }}
                    onClick={() => handleToggleBookmarkExpansion(bookmark.id)}
                />
            )}
            {bookmark.file && bookmark.file.length > 0 && (
                <div
                    className="file-attachment"
                    style={{
                        height: expandedBookmarks.has(bookmark.id) ? 'auto' : '130px',
                        overflow: expandedBookmarks.has(bookmark.id) ? 'visible' : 'hidden'
                    }}
                >
                    {bookmark.file.map((f, index) => (
                        f.type.startsWith('image/') ? (
                            <img
                                key={index}
                                src={f.url}
                                alt={f.name}
                                className="attachment-image"
                                style={{
                                    transform: `scale(${f.scale || 1})`,
                                    transformOrigin: 'center center',
                                    maxHeight: 'none',
                                    maxWidth: 'none',
                                    width: 'auto',
                                    height: 'auto'
                                }}
                            />
                        ) : f.type.startsWith('video/') ? (
                            <video
                                key={index}
                                src={f.url}
                                className="attachment-video"
                                style={{
                                    transform: `scale(${f.scale || 1})`,
                                    transformOrigin: 'center center',
                                    maxHeight: '100px',
                                    maxWidth: '100px'
                                }}
                            >
                                Ваш браузер не поддерживает видео.
                            </video>
                        ) : (
                            <div key={index} className="attachment-file">
                                <span className="file-icon">📎</span>
                                {f.name}
                            </div>
                        )
                    ))}
                </div>
            )}
            {/* ✅ Используем formatDate вместо хука */}
            <div className='bookmark_date'>{formatDate(bookmark.timestamp)}</div>

            {visibleOpcionId === bookmark.id && (
                <Suspense>
                    <OptionInPost
                        visibleOpcionId={visibleOpcionId}
                        itemId={bookmark.id}
                        showBookmarkSuccess={showBookmarkSuccess}
                        selectedMessageId={selectedMessageId}
                        showCopySuccess={showCopySuccess}
                        isBookmarked={true}
                        bookmarkId={isCustom ? bookmark.id : null}
                        currentMessages={activeTab === 'bookmarks' ? bookmarkedPosts : customBookmarks}
                        setEditingMessageId={setEditingMessageId}
                        setEditingText={setEditingText}
                        setVisibleOpcionId={setVisibleOpcionId}
                        setShowCopySuccess={setShowCopySuccess}
                        setSelectedMessageId={setSelectedMessageId}
                        setShowDeleteModal={setShowDeleteModal}
                        bookmarkedPosts={bookmarkedPosts}
                        setBookmarkedPosts={setBookmarkedPosts}
                        setShowBookmarkSuccess={setShowBookmarkSuccess}
                        setShowInput={setShowInput}
                        setInputText={setInputText}
                        customBookmarks={customBookmarks}
                        hideBookmarkIcons={true}
                        isInBookmarkModal={true}
                        setCustomBookmarkText={setCustomBookmarkText}
                        setShowTextInput={setShowTextInput}
                        onAddToPosts={handleAddToPostsClick}
                    />
                </Suspense>
            )}
        </div>
    );

    return (
        <>
            <div className='bookmark_block_modal'>
                <div className='delete_all_flex' onClick={() => {
                    if (activeTab === 'bookmarks') {
                        setShowDeleteAllBookmarkModal(true);
                    } else if (activeTab === 'text') {
                        setShowDeleteAllCustomBookmarkModal(true);
                    }
                }}>
                    <PiTrashThin className='remove_all' />
                    {activeTab === 'bookmarks' ? 'Удалить все закладки' : 'Удалить все текста'}
                </div>

                <PiBackspaceThin className='close_bookmark' onClick={handleCloseBookmark} />
                <div className='bookmark_content'>
                    <div className='marke_text'>
                        <CiSearch className='search_bookmarke' onClick={handleSearchClick} />
                        <div
                            className={`fon_bookmarke ${activeTab === 'bookmarks' ? 'active' : ''}`}
                            onClick={() => handleTabChange('bookmarks')}
                        >
                            Закладки {bookmarkedPosts.length}
                        </div>

                        <div
                            className={activeTab === 'text' ? 'active' : ''}
                            onClick={() => handleTabChange('text')}
                        >
                            Текст {customBookmarks.length}
                        </div>
                    </div>

                    {showSearchFields && (
                        <div className='search_fields'>
                            <input
                                type="text"
                                id="search-text-input"
                                name="searchText"
                                placeholder="Поиск по тексту..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className='search_input'
                            />
                            <div className='search_date_wrapper'>
                                <input
                                    type="date"
                                    id="search_date"
                                    name="search_date"
                                    value={searchDate}
                                    onChange={(e) => setSearchDate(e.target.value)}
                                    className='search_date'
                                    required
                                />
                            </div>
                        </div>
                    )}

                    {activeTab === 'bookmarks' ? (
                        <div>
                            {showTextInput ? (
                                <div className='text_input_container'>
                                    <InputMessage
                                        placeholder='Текст'
                                        value={customBookmarkText}
                                        onChange={setCustomBookmarkText}
                                        onSend={() => handleCustomBookmarkSend(customBookmarkText)}
                                        onCancel={handleCustomBookmarkClose}
                                        autoFocus
                                    />
                                </div>
                            ) : null}
                            {filteredBookmarkedPosts.length > 0 ? (
                                filteredBookmarkedPosts.map(bookmark => renderBookmarkItem(bookmark, false))
                            ) : (
                                <div className="no-bookmarks-message">
                                    ( Пусто )
                                </div>
                            )}
                        </div>
                    ) : (
                        <div>
                            {!showTextInput ? (
                                <div className='create_bookmark_block' onClick={handleTextInputToggle}>
                                    Создать
                                </div>
                            ) : (
                                <div className='text_input_container'>
                                    <InputMessage
                                        placeholder='Текст'
                                        value={customBookmarkText}
                                        onChange={setCustomBookmarkText}
                                        onSend={() => handleCustomBookmarkSend(customBookmarkText, selectedFile)}
                                        onCancel={handleCustomBookmarkClose}
                                        onFileSelect={handleFileSelect}
                                        selectedFile={selectedFile}
                                    />
                                </div>
                            )}

                            {filteredCustomBookmarks.length > 0 ? (
                                filteredCustomBookmarks.map(bookmark => renderBookmarkItem(bookmark, true))
                            ) : (
                                <div className="no-bookmarks-message">
                                    ( Пусто )
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {showDeleteBookmarkModal && (
                <WinModalQuest
                    onClose={cancelDeleteBookmark}
                    onConfirm={confirmDeleteBookmark}
                >
                    Удалить закладку?
                </WinModalQuest>
            )}

            {showDeleteCustomBookmarkModal && (
                <WinModalQuest
                    onClose={cancelDeleteCustomBookmark}
                    onConfirm={confirmDeleteCustomBookmark}
                >
                    Удалить текст?
                </WinModalQuest>
            )}

            {showDeleteAllBookmarkModal && (
                <WinModalQuest
                    onClose={() => setShowDeleteAllBookmarkModal(false)}
                    onConfirm={() => {
                        handleDeleteBookmarkClick(null);
                        setShowDeleteAllBookmarkModal(false);
                    }}
                >
                    Удалить все закладки?
                </WinModalQuest>
            )}

            {showDeleteAllCustomBookmarkModal && (
                <WinModalQuest
                    onClose={() => setShowDeleteAllCustomBookmarkModal(false)}
                    onConfirm={() => {
                        handleDeleteCustomBookmarkClick(null);
                        setShowDeleteAllCustomBookmarkModal(false);
                    }}
                >
                    Удалить все текста?
                </WinModalQuest>
            )}

            {showAddToPostsModal && (
                <WinModalQuest
                    onClose={cancelAddToPosts}
                    onConfirm={confirmAddToPosts}
                >
                    Добавить в посты?
                </WinModalQuest>
            )}

            {showDeleteModal && (
                <WinModalQuest
                    onClose={() => setShowDeleteModal(false)}
                    onConfirm={() => {
                        if (selectedMessageId) {
                            if (activeTab === 'bookmarks') {
                                const bookmark = bookmarkedPosts.find(b => b.id === selectedMessageId);
                                handleDeleteBookmarkClick(bookmark);
                            } else {
                                handleDeleteCustomBookmarkClick(customBookmarks.find(b => b.id === selectedMessageId));
                            }
                            setSelectedMessageId(null);
                        }
                        setShowDeleteModal(false);
                    }}
                >
                    Удалить?
                </WinModalQuest>
            )}
        </>
    );
});

BookmarkModal.displayName = 'BookmarkModal';

export default BookmarkModal;